{
  "sentences": [
    {
      "text": "我喜歡拍照，你呢？",
      "pinyin": "Wǒ xǐhuān pāizhào, nǐ ne?",
      "pinyin_numeric": "wo3 xi3huan1 pai1zhao4, ni3 ne0",
      "translation_en": "I like taking photos. How about you?",
      "translation_ko": "저는 사진 찍는 것을 좋아해요. 당신은요?"
    },
    {
      "text": "我最近很忙，你呢？",
      "pinyin": "Wǒ zuìjìn hěn máng, nǐ ne?",
      "pinyin_numeric": "wo3 zui4jin4 hen3 mang2, ni3 ne0",
      "translation_en": "I've been busy lately. How about you?",
      "translation_ko": "저는 요즘 바빠요. 당신은요?"
    },
    {
      "text": "我週末打算去台北，你呢？",
      "pinyin": "Wǒ zhōumò dǎsuàn qù Táiběi, nǐ ne?",
      "pinyin_numeric": "wo3 zhou1mo4 da3suan4 qu4 Tai2bei3, ni3 ne0",
      "translation_en": "I plan to go to Taipei this weekend. How about you?",
      "translation_ko": "저는 주말에 타이베이에 갈 계획이에요. 당신은요?"
    },
    {
      "text": "我喜歡吃台灣小吃，你呢？",
      "pinyin": "Wǒ xǐhuān chī Táiwān xiǎochī, nǐ ne?",
      "pinyin_numeric": "wo3 xi3huan1 chi1 Tai2wan1 xiao3chi1, ni3 ne0",
      "translation_en": "I like eating Taiwanese street food. How about you?",
      "translation_ko": "저는 대만 길거리 음식을 좋아해요. 당신은요?"
    },
    {
      "text": "我對音樂很有興趣，你呢？",
      "pinyin": "Wǒ duì yīnyuè hěn yǒu xìngqù, nǐ ne?",
      "pinyin_numeric": "wo3 dui4 yin1yue4 hen3 you3 xing4qu4, ni3 ne0",
      "translation_en": "I'm very interested in music. How about you?",
      "translation_ko": "저는 음악에 관심이 많아요. 당신은요?"
    },
    {
      "text": "我昨天去過夜市，你呢？",
      "pinyin": "Wǒ zuótiān qù guò yèshì, nǐ ne?",
      "pinyin_numeric": "wo3 zuo2tian1 qu4 guo4 ye4shi4, ni3 ne0",
      "translation_en": "I went to the night market yesterday. How about you?",
      "translation_ko": "저는 어제 야시장에 갔었어요. 당신은요?"
    },
    {
      "text": "我覺得這家餐廳不錯，你呢？",
      "pinyin": "Wǒ juéde zhè jiā cāntīng bùcuò, nǐ ne?",
      "pinyin_numeric": "wo3 jue2de0 zhe4 jia1 can1ting1 bu4cuo4, ni3 ne0",
      "translation_en": "I think this restaurant is pretty good. How about you?",
      "translation_ko": "저는 이 식당이 괜찮다고 생각해요. 당신은요?"
    },
    {
      "text": "我喜歡運動，你呢？",
      "pinyin": "Wǒ xǐhuān yùndòng, nǐ ne?",
      "pinyin_numeric": "wo3 xi3huan1 yun4dong4, ni3 ne0",
      "translation_en": "I like sports. How about you?",
      "translation_ko": "저는 운동을 좋아해요. 당신은요?"
    },
    {
      "text": "我最近在看一本書，你呢？",
      "pinyin": "Wǒ zuìjìn zài kàn yī běn shū, nǐ ne?",
      "pinyin_numeric": "wo3 zui4jin4 zai4 kan4 yi1 ben3 shu1, ni3 ne0",
      "translation_en": "I've been reading a book recently. How about you?",
      "translation_ko": "저는 요즘 책 한 권을 읽고 있어요. 당신은요?"
    },
    {
      "text": "我下個星期有空，你呢？",
      "pinyin": "Wǒ xià ge xīngqī yǒu kòng, nǐ ne?",
      "pinyin_numeric": "wo3 xia4 ge0 xing1qi1 you3 kong4, ni3 ne0",
      "translation_en": "I'll be free next week. How about you?",
      "translation_ko": "저는 다음 주에 시간이 있어요. 당신은요?"
    }
  ]
}
